using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

var errors = new List<(string Project, string Code, string Message, string File, int Line)>();
var warnings = new List<(string Project, string Code, string Message, string File, int Line)>();

build.VisitAllChildren<Error>(error => {
    var project = "";
    var node = (BaseNode)error;
    while (node.Parent != null) {
        node = (BaseNode)node.Parent;
        if (node is Project p) { project = p.Name; break; }
    }
    errors.Add((project, error.Code ?? "", error.Text ?? "", error.File ?? "", error.LineNumber));
});

build.VisitAllChildren<Warning>(warning => {
    var project = "";
    var node = (BaseNode)warning;
    while (node.Parent != null) {
        node = (BaseNode)node.Parent;
        if (node is Project p) { project = p.Name; break; }
    }
    if (warning.Code == "MSB3202" || warning.Code == "MSB4181" || (warning.Text ?? "").Contains("could not be resolved"))
        warnings.Add((project, warning.Code ?? "", warning.Text ?? "", warning.File ?? "", warning.LineNumber));
});

Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

var byProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in byProject) {
    Console.WriteLine($"=== Project: {group.Key} ===");
    foreach (var e in group.OrderBy(x => x.File).ThenBy(x => x.Line)) {
        Console.WriteLine($"  [{e.Code}] {e.File}({e.Line}): {e.Message}");
    }
    Console.WriteLine();
}

if (warnings.Any()) {
    Console.WriteLine("=== Relevant Warnings ===");
    foreach (var w in warnings.Take(20)) {
        Console.WriteLine($"  [{w.Code}] {w.Project}: {w.Message}");
    }
}
EOF
