using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = "/tmp/sv-0a6f11735bd74f9d80b3b599af6d1417/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Check all projects and their results
Console.WriteLine("=== All Projects Build Results ===");
build.VisitAllChildren<Project>(p => {
    var succeeded = p.Succeeded;
    Console.WriteLine($"  {p.Name} -> {(succeeded ? "SUCCEEDED" : "FAILED")}");
});

Console.WriteLine();

// Look at project references to understand dependencies
Console.WriteLine("=== Project References & Dependencies ===");
build.VisitAllChildren<Item>(item => {
    if (item.Name == "ProjectReference") {
        var parent = (BaseNode)item;
        while (parent.Parent != null) {
            parent = (BaseNode)parent.Parent;
            if (parent is Project p) { 
                Console.WriteLine($"  {p.Name} -> references -> {item.Text}");
                break; 
            }
        }
    }
});

Console.WriteLine();

// Look at package references for Services project
Console.WriteLine("=== Package References in Failed Projects ===");
build.VisitAllChildren<Item>(item => {
    if (item.Name == "PackageReference") {
        var parent = (BaseNode)item;
        while (parent.Parent != null) {
            parent = (BaseNode)parent.Parent;
            if (parent is Project p && p.Name == "Services.csproj") { 
                Console.WriteLine($"  {p.Name}: PackageReference -> {item.Text}");
                break; 
            }
        }
    }
});

// Look for NuGet restore issues
Console.WriteLine();
Console.WriteLine("=== NuGet/Restore Warnings ===");
build.VisitAllChildren<Warning>(w => {
    if ((w.Code ?? "").StartsWith("NU") || (w.Text ?? "").Contains("package") || (w.Text ?? "").Contains("restore")) {
        Console.WriteLine($"  [{w.Code}] {w.Text}");
    }
});
EOF
