using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = "/tmp/sv-0a6f11735bd74f9d80b3b599af6d1417/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Get package reference details
Console.WriteLine("=== Package References (AddItem details) ===");
build.VisitAllChildren<AddItem>(ai => {
    if (ai.Name == "PackageReference") {
        var parent = (BaseNode)ai;
        string proj = "";
        while (parent.Parent != null) {
            parent = (BaseNode)parent.Parent;
            if (parent is Project p) { proj = p.Name; break; }
        }
        foreach (var child in ai.Children) {
            if (child is Item item) {
                Console.WriteLine($"  {proj}: {item.Text}");
                foreach (var meta in item.Children.OfType<Metadata>()) {
                    Console.WriteLine($"      {meta.Name} = {meta.Value}");
                }
            }
        }
    }
});

// Check for MSB4181 or project reference failures
Console.WriteLine();
Console.WriteLine("=== Build Messages about failed references ===");
build.VisitAllChildren<Message>(m => {
    var text = m.Text ?? "";
    if (text.Contains("failed") || text.Contains("not found") || text.Contains("could not")) {
        if (!text.Contains("namespace")) // skip the CS0246 dupes
            Console.WriteLine($"  {text.Substring(0, Math.Min(text.Length, 200))}");
    }
});

// Look for project dependency structure
Console.WriteLine();
Console.WriteLine("=== ProjectReference Items ===");
build.VisitAllChildren<AddItem>(ai => {
    if (ai.Name == "ProjectReference") {
        var parent = (BaseNode)ai;
        string proj = "";
        while (parent.Parent != null) {
            parent = (BaseNode)parent.Parent;
            if (parent is Project p) { proj = p.Name; break; }
        }
        foreach (var child in ai.Children) {
            if (child is Item item) {
                Console.WriteLine($"  {proj} -> {item.Text}");
            }
        }
    }
});

// Check build result per target
Console.WriteLine();
Console.WriteLine("=== Failed Targets ===");
build.VisitAllChildren<Target>(t => {
    if (!t.Succeeded) {
        var parent = (BaseNode)t;
        string proj = "";
        while (parent.Parent != null) {
            parent = (BaseNode)parent.Parent;
            if (parent is Project p) { proj = p.Name; break; }
        }
        Console.WriteLine($"  {proj}: Target '{t.Name}' FAILED");
    }
});
EOF
